import{_ as e,o as t,c as r,a2 as i}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"F13: 資本支出效能與股利防禦 - 財務審計專家報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6239_力成/20260617/F13_資本支出效能與股利防禦.md","filePath":"審計報告庫/財務審計/6239_力成/20260617/F13_資本支出效能與股利防禦.md"}'),l={name:"審計報告庫/財務審計/6239_力成/20260617/F13_資本支出效能與股利防禦.md"};function o(n,a,h,s,d,p){return t(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="f13-資本支出效能與股利防禦-財務審計專家報告" tabindex="-1">F13: 資本支出效能與股利防禦 - 財務審計專家報告 <a class="header-anchor" href="#f13-資本支出效能與股利防禦-財務審計專家報告" aria-label="Permalink to &quot;F13: 資本支出效能與股利防禦 - 財務審計專家報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>資本支出的投入效能為何？自由現金流是否足以支撐其股利政策？是否存在「借債配息」之虛耗現象？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：CapEx/營收比從19.5%飆至25.9%。折舊122.3億佔營收16.3%。FCF轉負-93.3億。每年配息7元但股利防禦力短期尚可、長期承壓。</li><li><strong>風險評級</strong>：中</li><li><strong>數據時效</strong>：根據截至2025年最新年報數據</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>CapEx回報率檢驗：2020-2024年CapEx投入（53.0+98.6億）對應2024年營收733.2億（+95.1億較2022低點），CapEx增量產出比約0.63，效率中等。2025年CapEx 260.2億目標對應2026年營收預估850-900億（管理層高個位數至雙位數成長），若目標達成CapEx回報率有望提升。FCF覆蓋股利：2025年FCF -93.3億，帳面無法覆蓋股利51.7億，但現金流量表顯示股利係從營運現金流支付（CFO 167.0億足夠），無借債配息。歷年股利：6.8元(2021)→7.0元(2022)→7.0元(2023)→7.0元(2024)→4.5元(2025擬議)，2025年降息反映EPS下滑+擴產資金需求。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="capex效能回顧" tabindex="-1">CapEx效能回顧 <a class="header-anchor" href="#capex效能回顧" aria-label="Permalink to &quot;CapEx效能回顧&quot;">​</a></h3><p>力成近三年CapEx與營收成長對照：2023年CapEx 53.0億→2024年營收+6.4%；2024年CapEx 98.6億→2025年營收+2.2%；2025年CapEx 260.2億→2026年營收目標高個位數至雙位數成長。前兩期CapEx回報率偏低（營收增額/CapEx約0.2-0.5倍），但2025-2026年CapEx主要用於FOPLP/HBM等先進封裝，量產時間在2027年，回報尚未反映。此屬正常的「投資領先營收」週期，需待2027年觀察效能。</p><h3 id="股利安全性分析" tabindex="-1">股利安全性分析 <a class="header-anchor" href="#股利安全性分析" aria-label="Permalink to &quot;股利安全性分析&quot;">​</a></h3><p>2025年CFO 167.0億足以覆蓋擬議股利51.7億（含分配予母公司3.4億+非控制權益10.6億），現金股利支付率（CFO/股利）=3.2倍，安全性充足。但若以FCF計算（CFO-CapEx=-93.3億），股利覆蓋率為負，反映CapEx高峰已吃掉所有營運現金流。公司選擇降低現金股利7.0→4.5元（-36%），保留現金約18.6億用於擴產，為負責任的資本配置決策，非被迫降息。</p><h3 id="壓力測試" tabindex="-1">壓力測試 <a class="header-anchor" href="#壓力測試" aria-label="Permalink to &quot;壓力測試&quot;">​</a></h3><p>情境假設：2026年營收成長5%（至787億），毛利率回升至20%（營益率13%），CFO約180-190億，CapEx 400億（依管理層上修估算），FCF約-210至-220億。即使如此，CFO 180億仍足以支付股利約50億（假設維持4.5元）。股利安全性無虞，但FCF連續兩年為負需要舉債融資。若2027年營收達900億以上且CapEx放緩，FCF才會轉正。</p><h2 id="💡-專家評析-多空雙向分析" tabindex="-1">💡 專家評析（多空雙向分析） <a class="header-anchor" href="#💡-專家評析-多空雙向分析" aria-label="Permalink to &quot;💡 專家評析（多空雙向分析）&quot;">​</a></h2><h3 id="🔴-空方觀點-利空風險" tabindex="-1">🔴 空方觀點（利空風險） <a class="header-anchor" href="#🔴-空方觀點-利空風險" aria-label="Permalink to &quot;🔴 空方觀點（利空風險）&quot;">​</a></h3><ol><li><strong>CapEx效能指標全面惡化</strong>：CapEx/營收比逐年攀升（12.3%→15.3%→19.5%→25.9%），每1元營收需投入0.26元資本支出，資產周轉效率持續下降。</li><li><strong>股利防禦力被侵蝕</strong>：股利發放率從67%升至99%，幾乎將所有淨利配出。FCF為負、現金水位下降，若2027年淨利被折舊壓縮，可能被迫調降股利。</li></ol><h3 id="🟢-多方觀點-機會可能性" tabindex="-1">🟢 多方觀點（機會可能性） <a class="header-anchor" href="#🟢-多方觀點-機會可能性" aria-label="Permalink to &quot;🟢 多方觀點（機會可能性）&quot;">​</a></h3><ol><li><strong>股利紀錄穩定且具競爭力</strong>：連續4年配息7元，股息率約2-3%（同業日月光~3.5%），對收益型投資人仍具吸引力。</li><li><strong>CapEx集中於未來成長</strong>：400億用於FOPLP/HBM/CPO設備。折舊高峰後有機會將CapEx降至正常化水準，屆時FCF將大幅反轉。</li></ol><h3 id="⚖️-綜合權衡" tabindex="-1">⚖️ 綜合權衡 <a class="header-anchor" href="#⚖️-綜合權衡" aria-label="Permalink to &quot;⚖️ 綜合權衡&quot;">​</a></h3><p>CapEx效能持續下滑為結構性疑慮，但主因策略性擴產非營運糟化。股利態度顯示管理層重視股東回饋，但若FCF持續為負將考驗長期配息能力。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>計算工具：財務分析工具.py (capex_efficiency 6239)</li><li>原始數據：FinMind TaiwanStockCashFlowsStatement、TaiwanStockDividend</li><li>查詢參數：stock_id=6239, start=2022-01-01, end=2025-12-31</li><li>年報數據：2025_Q4_6239_合併.pdf (page 49，股利政策)</li><li>年報數據：2025_Q4_6239_合併.pdf (pages 12-13，現金流量表)</li><li>數據查詢日期：2026-06-17</li></ul>',23)])])}const C=e(l,[["render",o]]);export{_ as __pageData,C as default};
